library(tidyverse)
library(plotly)
library(pROC)

# ── Load predictions ──────────────────────────────────────────────────────────
# Generated by: python scripts/export_predictions.py
# Model: XGBoost with running roster BPM, travel features, player impact
preds <- read_csv("data/predictions_2026.csv", show_col_types = FALSE) %>%
  mutate(
    date       = as.Date(date),
    month      = factor(format(date, "%b"), levels = month.abb),
    correct    = as.integer((predicted_prob >= 0.5) == home_winner),
    outcome    = ifelse(home_winner == 1, "Home Win", "Away Win"),
    confidence = abs(predicted_prob - 0.5) + 0.5
  )

# ── Load market odds ─────────────────────────────────────────────────────────
odds <- read_csv("data/game_odds_2026.csv", show_col_types = FALSE)

# Remove vig to get fair market probability
odds <- odds %>%
  mutate(
    total_implied = home_implied_prob + away_implied_prob,
    market_prob   = home_implied_prob / total_implied
  )

# Subset of predictions that have market odds
preds_with_odds <- preds %>%
  inner_join(odds, by = "game_id") %>%
  filter(!is.na(market_prob))

# ── Print summary stats ───────────────────────────────────────────────────────
model_acc    <- mean(preds$correct)
model_acc_o  <- mean((preds_with_odds$predicted_prob >= 0.5) == preds_with_odds$home_winner)
market_acc   <- mean((preds_with_odds$market_prob >= 0.5) == preds_with_odds$home_winner)

cat(sprintf("Total 2026 games:                      %d\n", nrow(preds)))
cat(sprintf("Games with market odds:                 %d\n", nrow(preds_with_odds)))
cat(sprintf("Model accuracy (all games):             %.1f%%\n", model_acc * 100))
cat(sprintf("Model accuracy (games with odds):       %.1f%%\n", model_acc_o * 100))
cat(sprintf("Market accuracy (games with odds):      %.1f%%\n", market_acc * 100))
cat(sprintf("Model edge over market:                 %+.1f pp\n", (model_acc_o - market_acc) * 100))

# ── Compute ROC curves ───────────────────────────────────────────────────────
roc_model  <- roc(preds_with_odds$home_winner, preds_with_odds$predicted_prob, quiet = TRUE)
auc_model  <- round(auc(roc_model), 3)

roc_market <- roc(preds_with_odds$home_winner, preds_with_odds$market_prob, quiet = TRUE)
auc_market <- round(auc(roc_market), 3)

cat(sprintf("Model AUC:                              %.3f\n", auc_model))
cat(sprintf("Market AUC:                             %.3f\n", auc_market))

# Tidy ROC coordinates
roc_model_df <- tibble(
  fpr       = 1 - roc_model$specificities,
  tpr       = roc_model$sensitivities,
  threshold = roc_model$thresholds,
  source    = "Model"
) %>% arrange(fpr, tpr)

roc_market_df <- tibble(
  fpr       = 1 - roc_market$specificities,
  tpr       = roc_market$sensitivities,
  threshold = roc_market$thresholds,
  source    = "Market"
) %>% arrange(fpr, tpr)

roc_combined <- bind_rows(roc_model_df, roc_market_df)

# ── Map each game to its position on the model ROC curve ─────────────────────
game_roc <- preds_with_odds %>%
  rowwise() %>%
  mutate(
    roc_idx = which.min(abs(roc_model_df$threshold - predicted_prob)),
    fpr     = roc_model_df$fpr[roc_idx],
    tpr     = roc_model_df$tpr[roc_idx]
  ) %>%
  ungroup()

set.seed(42)
game_roc <- game_roc %>%
  mutate(
    fpr_jitter = fpr + rnorm(n(), 0, 0.008),
    tpr_jitter = tpr + rnorm(n(), 0, 0.008),
    tooltip = paste0(
      away_team, " @ ", home_team, "\n",
      format(date, "%b %d, %Y"), "\n",
      "Model P(Home) = ", scales::percent(predicted_prob, 0.1), "\n",
      "Market P(Home) = ", scales::percent(market_prob, 0.1), "\n",
      "Result: ", outcome
    )
  )

# ── 1. ROC Curve Plot ────────────────────────────────────────────────────────
p_roc <- ggplot() +
  geom_segment(
    aes(x = 0, y = 0, xend = 1, yend = 1),
    linetype = "dashed", color = "gray60", linewidth = 0.5
  ) +
  geom_point(
    data = game_roc,
    aes(x = fpr_jitter, y = tpr_jitter, color = outcome, text = tooltip),
    alpha = 0.2, size = 0.8
  ) +
  geom_line(
    data = roc_market_df,
    aes(x = fpr, y = tpr),
    color = "#e74c3c", linewidth = 1.1
  ) +
  geom_line(
    data = roc_model_df,
    aes(x = fpr, y = tpr),
    color = "#1a1a2e", linewidth = 1.1
  ) +
  annotate("text", x = 0.62, y = 0.28, hjust = 0, size = 4.2,
           label = paste0("Model AUC = ", auc_model), color = "#1a1a2e",
           fontface = "bold") +
  annotate("text", x = 0.62, y = 0.20, hjust = 0, size = 4.2,
           label = paste0("Market AUC = ", auc_market), color = "#e74c3c",
           fontface = "bold") +
  scale_color_manual(
    values = c("Home Win" = "#2196F3", "Away Win" = "#FF5722"),
    name   = "Actual Result"
  ) +
  labs(
    title    = "2026 CBB — Model vs Market ROC Curves",
    subtitle = paste0(
      format(nrow(preds_with_odds), big.mark = ","),
      " games  |  Model: ", model_acc_o * 100, "%  Market: ", market_acc * 100,
      "%  |  AUC ", auc_model, " vs ", auc_market
    ),
    x = "False Positive Rate",
    y = "True Positive Rate"
  ) +
  coord_equal(xlim = c(0, 1), ylim = c(0, 1)) +
  theme_minimal(base_size = 13) +
  theme(
    legend.position  = "bottom",
    plot.title       = element_text(face = "bold"),
    panel.grid.minor = element_blank()
  )

fig_roc <- ggplotly(p_roc, tooltip = "text") %>%
  layout(
    legend = list(orientation = "h", x = 0.3, y = -0.12),
    hoverlabel = list(bgcolor = "white", font = list(size = 12))
  )

# ── 2. Calibration Plot ──────────────────────────────────────────────────────
n_bins <- 10
cal_model <- preds_with_odds %>%
  mutate(bin = cut(predicted_prob, breaks = seq(0, 1, length.out = n_bins + 1),
                   include.lowest = TRUE)) %>%
  group_by(bin) %>%
  summarise(
    predicted = mean(predicted_prob),
    actual    = mean(home_winner),
    n         = n(),
    .groups   = "drop"
  ) %>%
  mutate(source = "Model")

cal_market <- preds_with_odds %>%
  mutate(bin = cut(market_prob, breaks = seq(0, 1, length.out = n_bins + 1),
                   include.lowest = TRUE)) %>%
  group_by(bin) %>%
  summarise(
    predicted = mean(market_prob),
    actual    = mean(home_winner),
    n         = n(),
    .groups   = "drop"
  ) %>%
  mutate(source = "Market")

cal_combined <- bind_rows(cal_model, cal_market)

p_cal <- ggplot(cal_combined, aes(x = predicted, y = actual, color = source)) +
  geom_abline(slope = 1, intercept = 0, linetype = "dashed", color = "gray60") +
  geom_point(aes(size = n, text = paste0(
    source, "\nPredicted: ", scales::percent(predicted, 0.1),
    "\nActual: ", scales::percent(actual, 0.1),
    "\nN = ", n
  )), alpha = 0.8) +
  geom_line(linewidth = 0.8) +
  scale_color_manual(values = c("Model" = "#1a1a2e", "Market" = "#e74c3c")) +
  scale_size_continuous(range = c(2, 8), guide = "none") +
  labs(
    title    = "Calibration: Model vs Market",
    subtitle = "Closer to diagonal = better calibrated",
    x = "Predicted Probability",
    y = "Observed Win Rate",
    color = NULL
  ) +
  coord_equal(xlim = c(0, 1), ylim = c(0, 1)) +
  theme_minimal(base_size = 13) +
  theme(
    legend.position  = "bottom",
    plot.title       = element_text(face = "bold"),
    panel.grid.minor = element_blank()
  )

fig_cal <- ggplotly(p_cal, tooltip = "text") %>%
  layout(
    legend = list(orientation = "h", x = 0.3, y = -0.12),
    hoverlabel = list(bgcolor = "white", font = list(size = 12))
  )

# ── 3. Monthly accuracy breakdown ────────────────────────────────────────────
monthly <- preds_with_odds %>%
  mutate(month = factor(format(date, "%b"), levels = month.abb)) %>%
  group_by(month) %>%
  summarise(
    n          = n(),
    model_acc  = mean((predicted_prob >= 0.5) == home_winner),
    market_acc = mean((market_prob >= 0.5) == home_winner),
    .groups    = "drop"
  ) %>%
  filter(n > 0)

monthly_long <- monthly %>%
  pivot_longer(cols = c(model_acc, market_acc),
               names_to = "source", values_to = "accuracy") %>%
  mutate(source = ifelse(source == "model_acc", "Model", "Market"))

p_monthly <- ggplot(monthly_long, aes(x = month, y = accuracy, fill = source)) +
  geom_col(position = "dodge", width = 0.6) +
  geom_text(aes(label = scales::percent(accuracy, 0.1)),
            position = position_dodge(0.6), vjust = -0.3, size = 3) +
  scale_fill_manual(values = c("Model" = "#1a1a2e", "Market" = "#e74c3c")) +
  scale_y_continuous(labels = scales::percent, limits = c(0, 1)) +
  labs(
    title = "Monthly Accuracy: Model vs Market",
    x = NULL, y = "Accuracy", fill = NULL
  ) +
  theme_minimal(base_size = 13) +
  theme(
    legend.position  = "bottom",
    plot.title       = element_text(face = "bold"),
    panel.grid.minor = element_blank()
  )

# ── Display plots ─────────────────────────────────────────────────────────────
fig_roc
fig_cal
ggplotly(p_monthly)
